VALUES
  ('optometrist-moex-00734', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡材質含水量的敘述，下列何者錯誤？', '["缺氧現象（hypoxia）較常與含水量低於 50% 的材質相關", "含矽水膠（siliconehydrogel）的軟式隱形眼鏡有較高的傳氧率（oxygentransmissibility）", "含水量高的水膠（hydrogel）軟式隱形眼鏡也能提高傳氧率", "含水量高的軟式隱形眼鏡模數（modulus）較低，因此不易操作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00735', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起角膜微笑型染色（smilestain）之敘述，下列何者錯誤？', '["因配戴軟式隱形眼鏡眨眼不完全，會導致水分流失引起角膜上皮的染色", "因配戴高含水量的軟式隱形眼鏡，若配戴時間過久易使淚水流失引起角膜上皮受損染色", "彈性較好的薄鏡片易造成角膜上側邊緣的上皮弧形受損染色，稱為微笑型染色", "配戴軟式隱形眼鏡因水分流失，引起角膜下側點狀上皮糜爛染色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00736', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者不是造成巨大乳突結膜炎（giantpapillaryconjunctivitis）的常見原因？', '["隱形眼鏡沉積物", "角膜新生血管", "眼內義眼片置放", "手術後角膜縫線突出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00737', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡急性紅眼症（contactlensacuteredeye,CLARE），下列敘述何者正確？', '["較常發生於兩眼", "常見於急性病毒感染", "病灶多位於角膜中央", "為細菌內毒素引起之發炎反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00738', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關鞏膜片的併發症，下列敘述何者錯誤？', '["由於鏡片較大，使用高透氣鏡片（highgas-permeablelens）亦無法改善缺氧的狀況", "常於鏡片後有黏液存在", "常於鏡片後有氣泡存在", "常造成結膜壓迫變白"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00739', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴鞏膜片（sclerallenses），如因角膜缺氧的早期症狀所產生之不適感，根據Ortenbergetal.（2013） 研究建議每日配戴鞏膜片的患者，每配戴多少小時後暫時休息一下，就可有明顯的改善？', '["4~5小時", "6~7小時", "8~9小時", "10~12小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00740', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關老花眼以單眼視法（monovision）矯正之敘述，下列何者正確？', '["65歲以上的遠視患者配老花眼，最適合採用此法矯正", "多數以利眼（dominanteye）矯正近方視力，用非主力眼（non-dominanteye）矯正遠方視力為主， 且適用於有屈光參差（anisometropia）者", "以單眼視法矯正老花眼的機制是視覺系統會抑制較模糊不清晰的影像，因此能看到遠方或近方的事物", "此法的優點包括經濟實惠、球面及散光的屈光度皆可矯正，所以遠近視力皆好、對比敏感度不受影 響，缺點是只適用於輕度老花者，其立體視覺不會改變且雙眼視覺舒適度變差"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00741', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關動態穩定設計之軟式散光鏡片，下列敘述何者錯誤？', '["目前軟式散光片最常用的穩定方法", "重力對穩定性影響不大", "鏡片厚度分布與眼瞼的相互作用是主要穩定因素", "對低球面度數的散光片而言，動態穩定設計優於垂重稜鏡設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00742', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者想要配硬式透氣隱形眼鏡。他以前的醫生在1年前給他配軟式鏡片，由於鏡片表面沉積物和指甲 易撕裂鏡片，他經歷了視力模糊和頻繁更換鏡片。 ODK44.00D@180/44.25D@090RX-3.25DS/-1.25DC×180 OSK43.50D@180/44.00D@090RX-3.00DS/-1.25DC×180 該患者下個鏡片應配戴什麼材質較適合？', '["超厚又低 DK硬式球面透氣鏡片", "年拋水膠", "雙散硬式透氣鏡片", "薄又高DK硬式球面透氣鏡片"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00743', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '最常見的散光硬式隱形眼鏡（rigidtoriclens），鏡片弧度設計為何？', '["後表面光學區複曲面設計（toroidalbackopticzone），邊區（peripheralzone）複曲面設計", "後表面光學區球面設計（sphericalbackopticzone），邊區複曲面設計", "後表面光學區複曲面設計，邊區球面設計", "後表面光學區及邊區球面設計，前表面光學區複曲面設計（toroidalfrontopticsurface）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
